{HoldPattern[GetSpins[gaugeGroup_, partReps_, partSpins_, partFlavours_]] :> Module[{allowedSpins, possibleSpins, maxSpin, testSpins, numFlav, product, refCharge, tProd, tPerm, fullGroup, labels, op, checks}, allowedSpins = {}; possibleSpins = {}; maxSpin = Count[partSpins, 2] + 1; testSpins = Table[i, {i, maxSpin, 1, -2}]; numFlav = Max[partFlavours]; product = Table[Join[{partReps[[i]], partSpins[[i]]}, IdentityMatrix[numFlav][[partFlavours[[i]]]]], {i, Length[partReps]}]; refCharge = -Total[product[[All,3 ;; All]]]; fullGroup = Join[{gaugeGroup, SU2}, Table[U1, {i, numFlav}]]; labels = -1; Do[tProd = Append[product, Join[{1, tspin}, refCharge]]; tPerm = PermutationSymmetryOfInvariants[fullGroup, tProd]; If[Length[tPerm[[2]]] > 0, AppendTo[possibleSpins, {tspin, tPerm[[2]]}]]; If[labels == -1, labels = tPerm[[1,All]]]; , {tspin, testSpins}]; possibleSpins[[All,2,All,1]] = possibleSpins[[All,2,All,1,1 ;; -2]]; labels = labels[[1 ;; -2]]; Do[checks = True; Do[op = tspin[[2,1,1,l]]; If[partSpins[[labels[[l,1]]]] == 2, If[Length[labels[[l]]] != Length[op], checks = False; Break[]; ]; , If[Length[labels[[l]]] != op[[1]], checks = False; Break[]; ]; ], {l, Length[labels]}]; If[checks, AppendTo[allowedSpins, {tspin[[1]], tspin[[-1,-1,-1]]}]]; , {tspin, possibleSpins}]; allowedSpins]}